	c.Put("a", 1); c.Put("b", 2)
	if evicted != 1 { t.Fatalf("expected 1, got %d", evicted) }
}

func TestCache_Capacity(t *testing.T) {
	c := NewCache(42)
	if c.Capacity() != 42 { t.Fatal("wrong capacity") }
